  return <h1>Kateqoriya: {params.slug}</h1>;
}

console.log('Dərin qovluq strukturu yaradıldı');

// app/layout.js (root)
export default function RootLayout({ children }) {
  return (
    <html>
      <body>
        <header>Ümumi Header</header>
        {children}
      </body>
    </html>
  );
}

// app/dashboard/layout.js
export default function DashboardLayout({ children }) {
  return (
    <div>
      <aside>Dashboard Sidebar</aside>
      <main>{children}</main>
    </div>
  );
}

